namespace sv_c4a9f2a9962249108346b262e0dc3061.Client.Models;

public class Shipment
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public required string Location { get; set; }
    public DateTime Timestamp { get; set; }
}

using sv_c4a9f2a9962249108346b262e0dc3061.Client.Models;

namespace sv_c4a9f2a9962249108346b262e0dc3061.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_c4a9f2a9962249108346b262e0dc3061.Client.Models;
using sv_c4a9f2a9962249108346b262e0dc3061.Client.Services;

namespace sv_c4a9f2a9962249108346b262e0dc3061.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new Shipment
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 6, 2, 17, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = new DateTime(2026, 5, 20, 9, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = new DateTime(2026, 5, 20, 14, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = new DateTime(2026, 5, 22, 6, 15, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "In transit to destination", Location = "Chicago, IL", Timestamp = new DateTime(2026, 5, 23, 8, 0, 0, DateTimeKind.Utc) },
            ]
        },
        ["TRK-2002"] = new Shipment
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 18, 12, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTime(2026, 5, 14, 10, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTime(2026, 5, 15, 16, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 17, 7, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 17, 14, 22, 0, DateTimeKind.Utc) },
            ]
        },
        ["TRK-3003"] = new Shipment
        {
            TrackingNumber = "TRK-3003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 5, 18, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 25, 11, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Awaiting pickup", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 25, 11, 5, 0, DateTimeKind.Utc) },
            ]
        }
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

using System.Net;
using System.Net.Http.Json;
using sv_c4a9f2a9962249108346b262e0dc3061.Client.Models;

namespace sv_c4a9f2a9962249108346b262e0dc3061.Client.Services;

public class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Received empty response from server.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_c4a9f2a9962249108346b262e0dc3061.Client.Models
@using sv_c4a9f2a9962249108346b262e0dc3061.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="alert alert-info">
        <span class="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
        Loading shipment details for <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h3>Shipment @_shipment.TrackingNumber</h3>

    <div class="card mb-3">
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Status</dt>
                <dd class="col-sm-9">@_shipment.Status</dd>

                <dt class="col-sm-3">Location</dt>
                <dd class="col-sm-9">@_shipment.Location</dd>

                <dt class="col-sm-3">Estimated Delivery</dt>
                <dd class="col-sm-9">
                    @(_shipment.EstimatedDelivery?.ToString("f") ?? "N/A")
                </dd>
            </dl>
        </div>
    </div>

    @if (_shipment.StatusUpdates.Count > 0)
    {
        <h5>Tracking History</h5>
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Location</th>
                    <th>Description</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;
    private string? _lastLoadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        // Only reload when the tracking number actually changes.
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase))
        {
            return;
        }

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request.
        CancelPending();

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Navigation or disposal triggered cancellation — don't show an error.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please check your connection and try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please check your connection and try again.";
        }
        catch (KeyNotFoundException)
        {
            _errorMessage = $"Shipment \"{TrackingNumber}\" was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        _lastLoadedTrackingNumber = null;
        await LoadShipmentAsync();
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

