@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_c4a9f2a9962249108346b262e0dc3061.Client.Models
@using sv_c4a9f2a9962249108346b262e0dc3061.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="alert alert-info">
        <span class="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
        Loading shipment details for <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h3>Shipment @_shipment.TrackingNumber</h3>

    <div class="card mb-3">
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Status</dt>
                <dd class="col-sm-9">@_shipment.Status</dd>

                <dt class="col-sm-3">Location</dt>
                <dd class="col-sm-9">@_shipment.Location</dd>

                <dt class="col-sm-3">Estimated Delivery</dt>
                <dd class="col-sm-9">
                    @(_shipment.EstimatedDelivery?.ToString("f") ?? "N/A")
                </dd>
            </dl>
        </div>
    </div>

    @if (_shipment.StatusUpdates.Count > 0)
    {
        <h5>Tracking History</h5>
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Location</th>
                    <th>Description</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;
    private string? _lastLoadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        // Only reload when the tracking number actually changes.
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase))
        {
            return;
        }

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request.
        CancelPending();

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Navigation or disposal triggered cancellation — don't show an error.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please check your connection and try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please check your connection and try again.";
        }
        catch (KeyNotFoundException)
        {
            _errorMessage = $"Shipment \"{TrackingNumber}\" was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        _lastLoadedTrackingNumber = null;
        await LoadShipmentAsync();
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

